// Split incoming contentPrompts into one item per platform
const { postId, contentPrompts, callbackUrl } = $input.first().json;

if (!postId || !contentPrompts || !callbackUrl) {
  throw new Error('Missing required fields: postId, contentPrompts, callbackUrl');
}

const items = [];
for (const [platform, prompts] of Object.entries(contentPrompts)) {
  if (!prompts || !prompts.systemPrompt || !prompts.userPrompt) {
    console.log(`Skipping ${platform} - missing systemPrompt or userPrompt`);
    continue;
  }
  items.push({
    json: {
      postId,
      platform,
      systemPrompt: prompts.systemPrompt,
      userPrompt: prompts.userPrompt,
      context: prompts.context || {},
      callbackUrl
    }
  });
}

if (items.length === 0) {
  throw new Error('No valid platforms with content prompts found');
}

return items;

// Parse AI response and extract text + hashtags
const postId = $('Code - Split by Platform').item.json.postId;
const platform = $('Code - Split by Platform').item.json.platform;
const callbackUrl = $('Code - Split by Platform').item.json.callbackUrl;
const context = $('Code - Split by Platform').item.json.context || {};

const response = $json;
const content = response?.choices?.[0]?.message?.content || '';

if (!content) {
  throw new Error(`OpenRouter returned empty content for ${platform}`);
}

// Extract hashtags (lines starting with # or words starting with #)
const hashtagMatches = content.match(/#[\w]+/g) || [];
const hashtags = [...new Set(hashtagMatches.map(h => h.replace('#', '').toLowerCase()))];

// Remove hashtag lines from the main text body for cleaner output
const text = content.trim();

const now = new Date().toISOString();

return [{
  json: {
    postId,
    platform,
    callbackUrl,
    text,
    hashtags,
    status: 'pending',
    generatedAt: now
  }
}];

// Aggregate all platform results and prepare callback
const items = $input.all();
const postId = items[0]?.json?.postId || items[0]?.json?.post_id || '';
const callbackUrl = $('Code - Parse AI Response').all()[0]?.json?.callbackUrl || '';

return [{
  json: {
    postId,
    callbackUrl,
    status: 'done',
    processedPlatforms: items.length
  }
}];

// Build error callback payload
const inputData = $input.first().json || {};
// Try to get callbackUrl from the original webhook data
let callbackUrl = '';
let postId = '';
try {
  callbackUrl = $('Webhook').first().json.callbackUrl || '';
  postId = $('Webhook').first().json.postId || '';
} catch(e) {}

return [{
  json: {
    postId,
    callbackUrl,
    status: 'failed',
    error: inputData.error?.message || 'Content generation failed'
  }
}];
